class Solution:
    def alternateDigitSum(self, n):
        digits = []
        m = n
        while m > 0:
            digits.append(m % 10)
            m //= 10
        digits.reverse()
        total = 0
        for i, d in enumerate(digits):
            total += d if i % 2 == 0 else -d
        return total

solutions.python:
class Solution:
    def alternateDigitSum(self, n):
        sign = 1
        total = 0
        for ch in str(n):
            total += sign * int(ch)
            sign = -sign
        return total

